3 Analiz

3.1 Keşifsel Veri Analizi

muhendislik |&gt;
  filter(!is.na(en_dusuk_puan)) |&gt;
  group_by(year, type) |&gt;
  summarise(ort_taban_puan = mean(en_dusuk_puan, na.rm = TRUE),
            .groups = "drop")

# A tibble: 0 × 3
# ℹ 3 variables: year &lt;int&gt;, type &lt;chr&gt;, ort_taban_puan &lt;dbl&gt;




3.2 Trend Analizi

muhendislik |&gt;
  filter(!is.na(en_dusuk_puan)) |&gt;
  group_by(year, type) |&gt;
  summarise(ort_taban_puan = mean(en_dusuk_puan, na.rm = TRUE),
            .groups = "drop") |&gt;
  ggplot(aes(x = year, y = ort_taban_puan, color = type, group = type)) +
  geom_line(size = 1) +
  geom_point(size = 3) +
  labs(
    title = "Makine Mühendisliği Taban Puanlarının Yıllara Göre Değişimi",
    x = "Yıl",
    y = "Ortalama Taban Puan",
    color = "Üniversite Türü"
  ) +
  theme_minimal()










3.3 Model Uydurma

muhendislik |&gt;
  filter(!is.na(en_dusuk_puan)) |&gt;
  group_by(type) |&gt;
  summarise(
    ort_taban = mean(en_dusuk_puan, na.rm = TRUE),
    min_taban = min(en_dusuk_puan, na.rm = TRUE),
    max_taban = max(en_dusuk_puan, na.rm = TRUE),
    .groups = "drop"
  )

# A tibble: 0 × 4
# ℹ 4 variables: type &lt;chr&gt;, ort_taban &lt;dbl&gt;, min_taban &lt;dbl&gt;, max_taban &lt;dbl&gt;
